const { BigQuery } = require('@google-cloud/bigquery');
const bigquery = new BigQuery();

exports.processLargeDataset = async (req, res) => {
  const { query, table } = req.body;
  
  try {
    const job = await bigquery.createQueryJob({
      query: query || `SELECT * FROM \`${table}\``,
      useQueryCache: true,
      useLegacySql: false,
      maximumBytesBilled: 10737418240 // 10GB limit
    });
    
    const [results] = await job[0].getResults();
    
    // Process results in chunks to avoid memory issues
    const batchSize = 1000;
    const aggregatedData = [];
    
    for (let i = 0; i < results.length; i += batchSize) {
      const batch = results.slice(i, i + batchSize);
      
      // Process batch
      const processedBatch = batch.map(row => {
        // Your data processing logic here
        return row;
      });
      
      aggregatedData.push(...processedBatch);
      
      // Allow other operations to run
      await new Promise(resolve => setImmediate(resolve));
    }
    
    res.status(200).json({
      success: true,
      totalRecords: results.length,
      processedData: aggregatedData
    });
    
  } catch (error) {
    console.error('Error processing dataset:', error);
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
};

